mapper.select:
SELECT hd.id, hd.function_type, CASE hd.function_type WHEN 'VEHICLE_MANAGE' THEN '车辆管理' WHEN 'BATTERY_CONFIG' THEN '电池配置' WHEN 'ALARM' THEN '报警提醒' WHEN 'SHARE' THEN '用车人管理' WHEN 'LOCATION' THEN '车辆位置' WHEN 'RIDING' THEN '骑行轨迹' END AS function_type_name, hd.title, hd.description FROM help_doc hd WHERE hd.deleted = 0 AND hd.status = '1'
AND hd.function_type = #{functionType}
ORDER BY hd.sort ASC
